"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

import { FlipUnit } from "./flip-unit"

interface Time {
  h: string
  m: string
  s: string
}

/**
 * Reads the current time as HH:MM:SS. Defaults to the viewer's own timezone
 * (via Intl — no geolocation prompt), reflecting their location; pass an IANA
 * `timeZone` (e.g. "Europe/London") to pin it.
 */
function useClock(timeZone?: string): Time | null {
  const [time, setTime] = React.useState<Time | null>(null)

  React.useEffect(() => {
    const fmt = new Intl.DateTimeFormat("en-GB", {
      timeZone,
      hour: "2-digit",
      minute: "2-digit",
      second: "2-digit",
      hourCycle: "h23",
    })

    const tick = () => {
      const parts = fmt.formatToParts(new Date())
      const get = (t: Intl.DateTimeFormatPartTypes) =>
        parts.find((p) => p.type === t)?.value ?? "00"
      setTime({ h: get("hour"), m: get("minute"), s: get("second") })
    }

    tick()
    // Poll faster than 1s so a second rollover flips promptly without drift.
    const id = setInterval(tick, 250)
    return () => clearInterval(id)
  }, [timeZone])

  return time
}

export function FlipClock({
  timeZone,
  className,
}: {
  timeZone?: string
  className?: string
}) {
  const time = useClock(timeZone)

  // Render nothing time-specific on the server to avoid hydration mismatch.
  if (!time) {
    return (
      <span
        aria-hidden
        className={cn(
          "inline-block h-[1.3rem] w-[6.2rem] animate-pulse rounded bg-muted align-middle",
          className
        )}
      />
    )
  }

  return (
    <span
      role="timer"
      aria-label={`${time.h}:${time.m}:${time.s}`}
      className={cn(
        // Muted + text-sm to sit alongside the copyright text.
        "inline-flex items-center gap-[0.12rem] align-middle font-mono text-sm leading-none text-muted-foreground [--fc-h:1.3rem] [--fc-w:0.85rem]",
        className
      )}
    >
      <Pair value={time.h} />
      <Separator />
      <Pair value={time.m} />
      <Separator />
      <Pair value={time.s} />
    </span>
  )
}

function Pair({ value }: { value: string }) {
  return (
    <span className="inline-flex gap-[0.1rem]">
      <FlipUnit digit={value[0]} />
      <FlipUnit digit={value[1]} />
    </span>
  )
}

function Separator() {
  return (
    <span aria-hidden className="px-[0.05rem] text-muted-foreground">
      :
    </span>
  )
}

"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

/** Total flip duration must match the CSS (fold-top + delayed fold-bottom). */
const FLIP_MS = 560

/**
 * A single split-flap digit. When `digit` changes, the top flap folds down
 * (showing the old digit) while the bottom flap folds up (revealing the new
 * one) — the classic flip-clock motion. Sizing comes from the `--fc-h` /
 * `--fc-w` CSS variables set by the parent <FlipClock>.
 */
export function FlipUnit({ digit }: { digit: string }) {
  const [state, setState] = React.useState({
    current: digit,
    previous: digit,
    flipping: false,
  })

  if (state.current !== digit) {
    setState((s) =>
      s.current === digit
        ? s
        : { current: digit, previous: s.current, flipping: true }
    )
  }

  React.useEffect(() => {
    if (!state.flipping) return
    const t = setTimeout(
      () => setState((s) => ({ ...s, flipping: false })),
      FLIP_MS
    )
    return () => clearTimeout(t)
  }, [state.flipping])

  const { current, previous, flipping } = state
  // Bottom static half keeps showing the old digit until the flip completes.
  const bottomStatic = flipping ? previous : current

  return (
    <span
      aria-hidden
      className="relative inline-block h-(--fc-h) w-(--fc-w) rounded-[0.18em] bg-muted text-muted-foreground select-none perspective-[220px]"
    >
      <Half half="top">{current}</Half>
      <Half half="bottom">{bottomStatic}</Half>

      {flipping && (
        <>
          <Half half="top" className="z-10 animate-flip-top">
            {previous}
          </Half>
          <Half half="bottom" className="z-10 animate-flip-bottom">
            {current}
          </Half>
        </>
      )}

      {/* Center hinge line */}
      <span
        aria-hidden
        className="absolute inset-x-0 top-1/2 z-20 h-px -translate-y-1/2 bg-background/50"
      />
    </span>
  )
}

function Half({
  half,
  className,
  children,
}: {
  half: "top" | "bottom"
  className?: string
  children: React.ReactNode
}) {
  return (
    <span
      className={cn(
        "absolute inset-x-0 flex h-1/2 overflow-hidden bg-muted",
        half === "top"
          ? "top-0 items-start rounded-t-[0.18em]"
          : "bottom-0 items-end rounded-b-[0.18em]",
        className
      )}
    >
      {/* A full-unit-height glyph clipped by the half window. items-start shows
          its top half; items-end shows its bottom half — together = one digit. */}
      <span className="block h-(--fc-h) w-full shrink-0 text-center leading-(--fc-h)">
        {children}
      </span>
    </span>
  )
}
